// PATCH: Implement Chrome LocalStorage token import now that LevelDB is available.

package cli

import (
	"fmt"
	"os"
	"path/filepath"
	"regexp"
	"strings"

	"github.com/spf13/cobra"
	"github.com/syndtr/goleveldb/leveldb"
	"github.com/mvanhorn/printing-press-library/library/developer-tools/yeswehack/internal/config"
)

func newAuthLoginCmd(flags *rootFlags) *cobra.Command {
	var chrome bool
	cmd := &cobra.Command{
		Use:     "login",
		Short:   "Import authentication from a browser session",
		Long:    "Import authentication from Chrome local storage when the optional LevelDB reader dependency is available.",
		Example: "  yeswehack-pp-cli auth login --chrome",
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) > 0 {
				return cmd.Help()
			}
			if dryRunOK(flags) {
				return nil
			}
			if !chrome {
				return fmt.Errorf("auth login currently requires --chrome; otherwise use yeswehack-pp-cli auth set-token <jwt>")
			}
			token, err := readChromeAccessToken()
			if err != nil {
				return err
			}
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}
			cfg.AuthHeaderVal = ""
			if err := cfg.SaveTokens("", "", token, "", cfg.TokenExpiry); err != nil {
				return configErr(fmt.Errorf("saving token: %w", err))
			}
			if flags.asJSON {
				return printJSONFiltered(cmd.OutOrStdout(), map[string]any{"saved": true, "config_path": cfg.Path, "source": "chrome"}, flags)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "Token imported from Chrome and saved to %s\n", cfg.Path)
			return nil
		},
	}
	cmd.Flags().BoolVar(&chrome, "chrome", false, "Read token from Chrome local storage")
	return cmd
}

func readChromeAccessToken() (string, error) {
	home, _ := os.UserHomeDir()
	dbPath := filepath.Join(home, "Library", "Application Support", "Google", "Chrome", "Default", "Local Storage", "leveldb")
	db, err := leveldb.OpenFile(dbPath, nil)
	if err != nil {
		if strings.Contains(strings.ToLower(err.Error()), "lock") {
			return "", fmt.Errorf("Chrome is running and the LocalStorage leveldb is locked. Quit Chrome and re-run, or paste the token: yeswehack-pp-cli auth set-token <jwt>")
		}
		return "", fmt.Errorf("opening Chrome LocalStorage leveldb: %w", err)
	}
	defer db.Close()
	jwtRe := regexp.MustCompile(`eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+`)
	iter := db.NewIterator(nil, nil)
	defer iter.Release()
	for iter.Next() {
		key := string(iter.Key())
		value := string(iter.Value())
		if !strings.Contains(key, "access_token") && !strings.Contains(value, "access_token") {
			continue
		}
		if token := jwtRe.FindString(value); token != "" {
			return token, nil
		}
		if token := jwtRe.FindString(key); token != "" {
			return token, nil
		}
	}
	if err := iter.Error(); err != nil {
		return "", err
	}
	return "", fmt.Errorf("no yeswehack.com access_token JWT found in Chrome Default profile LocalStorage")
}
